} from './Pipeline.utils'
import { PipelineStatusName } from './Replication.constants'

interface RowMenuProps {
  destinationId: number
  pipeline: Pipeline | undefined
  pipelineStatus?: ReplicationPipelineStatusData['status']
  error: ResponseError | null
  isLoading: boolean
  isError: boolean
  hasUpdate?: boolean
  onDeleteClick: () => void
  onUpdateClick?: () => void
}

